sql:
SELECT item_type, expiration_date, COUNT(*) AS total_items
FROM inventory_items
GROUP BY item_type, expiration_date;

SELECT expiration_date
FROM inventory_items
WHERE item_type = 'Medication';

SELECT patient_id, start_date
FROM patient_art
WHERE location_id = 1 AND retained = 0;

SELECT item_id, transaction_date, remarks
FROM inventory_records
WHERE transaction_type = 'redistributed';

SELECT item_id, stock_out_days
FROM stock_out_days
WHERE stock_out_days <= 30;

SELECT item_id, AVG(stock_out_days) AS average_unavailability_duration
FROM stock_out_days
GROUP BY item_id;

SELECT AVG(stock_out_days) AS avg_days_out_of_stock
FROM stock_out_days
WHERE location_id = 0;

SELECT COUNT(DISTINCT item_id) AS total_items_out_of_stock_in_april
FROM stock_out_days
WHERE strftime('%Y-%m', start_date) = '2023-04';

SELECT location_id, COUNT(record_id) AS transaction_count
FROM inventory_records
GROUP BY location_id;

SELECT supplier_name 
FROM suppliers 
WHERE supplier_id = (
    SELECT supplier_id 
    FROM inventory_items 
    WHERE reorder_level = (
        SELECT MIN(reorder_level) 
        FROM inventory_items
    )
);

SELECT COUNT(*) 
FROM stock_out_days
WHERE stock_out_days > 30;

SELECT description
FROM business_rules
ORDER BY priority ASC;

SELECT ii.item_name, ii.item_type
FROM inventory_items ii
WHERE ii.item_id IN (
    SELECT ro.item_id 
    FROM requisition_orders ro 
    WHERE ro.status = 'delivered'
) AND ii.item_id NOT IN (
    SELECT ir.item_id 
    FROM inventory_records ir
);

SELECT DISTINCT item_id
FROM stock_out_days
WHERE stock_out_days > 30;

external_knowledge:
- "Singing the alarm bells for urgent restocking" implies items that need to be reordered immediately due to stock-out days exceeding reorder levels;
- "Designated reorder threshold" refers to the reorder level column in the inventory_items table;
- "After the last distribution" means the transaction where the type is 'distributed' and it is the most recent transaction for each item.

